import os
import torch
import logging
import json
from torch.utils.tensorboard import SummaryWriter


def setup_logger(name: str, level=logging.INFO):
    logger = logging.getLogger(name)
    logger.setLevel(level)
    if not logger.handlers:
        handler = logging.StreamHandler()
        fmt = logging.Formatter("[%(asctime)s][%(name)s] %(message)s", datefmt="%H:%M:%S")
        handler.setFormatter(fmt)
        logger.addHandler(handler)
    return logger


class TBLogger:
    """Thin wrapper around SummaryWriter."""

    def __init__(self, log_dir: str):
        os.makedirs(log_dir, exist_ok=True)
        self.writer = SummaryWriter(log_dir=log_dir)

    def add_scalar(self, tag: str, value, step: int):
        self.writer.add_scalar(tag, value, step)

    def add_scalars(self, tag: str, dict_, step: int):
        self.writer.add_scalars(tag, dict_, step)

    def close(self):
        self.writer.close()


def save_checkpoint(model: torch.nn.Module, optimizer: torch.optim.Optimizer,
                    episode: int, reward: float, path: str):
    os.makedirs(os.path.dirname(path) if os.path.dirname(path) else ".", exist_ok=True)
    torch.save({
        "model_state_dict": model.state_dict(),
        "optimizer_state_dict": optimizer.state_dict(),
        "episode": episode,
        "reward": reward,
    }, path)


def load_checkpoint(path: str, model: torch.nn.Module, optimizer=None, device="cpu"):
    ckpt = torch.load(path, map_location=device, weights_only=False)
    model.load_state_dict(ckpt["model_state_dict"])
    if optimizer and "optimizer_state_dict" in ckpt:
        optimizer.load_state_dict(ckpt["optimizer_state_dict"])
    return ckpt.get("episode", 0), ckpt.get("reward", 0.0)


class RunningMeanStd:
    """Tracks running mean/std for reward normalization."""

    def __init__(self, epsilon=1e-4):
        self.mean = 0.0
        self.var = 1.0
        self.count = epsilon

    def update(self, x: float):
        self.count += 1
        delta = x - self.mean
        self.mean += delta / self.count
        delta2 = x - self.mean
        self.var += delta * delta2

    @property
    def std(self):
        return (self.var / self.count) ** 0.5 + 1e-8
